<template>
  <div class="background-block" v-bind:style="{ backgroundImage: mainBg}">
      <div class="shadow-block">
          <div class="container">
                <form v-on:submit.prevent="sendComment" class="feedback">
                    <p class="title">Спасибо за проведенную презентацию!</p>
                    <textarea placeholder="Оставить комментарий по презентации"></textarea>
                    <input type="submit" value="отправить">
                </form>
                <form class="signLink" v-on:submit.prevent="getLink">
                    <p class="title">Для того, чтобы получить приватную ссылку, заполните поле ниже</p>
                    <input 
                        type="text" 
                        name='email'
                        placeholder="Введите e-mail получателя"
                        v-model.trim="email"
                        :class="{error: ($v.email.$dirty && !$v.email.required) || ($v.email.$dirty && !$v.email.email)}">
                        <label 
                            class="error"
                            v-if="$v.email.$dirty && !$v.email.required">
                            Поле 'E-mail' не должно быть пустым
                        </label>
                        <label 
                            class="error"
                            v-else-if="$v.email.$dirty && !$v.email.email">
                            Введите корректный e-mail
                        </label>
                    <input type="submit" value="отправить">
                </form>
                <div class="responseLink">
                    <p class="title">Также вы можете скопировать данную ссылку</p>
                    <p @click='copyLink' id="newLink">{{newLink}}</p>
                    <a href="#" v-on:click.prevent="$router.push('\collections')">Вернуться в коллекции</a>
                </div>
          </div>
      </div>
    </div>
</template>
<script>
import settings from '../settings'
import {email, required} from 'vuelidate/lib/validators';
export default {
    data: () => ({
        mainBg: 'url('+ require('../img/background.png') +')',
        email: '',
        newLink: "http://localhost:8080http://localh"
    }),
    validations: {
        email: {email, required}
    },
    methods: {
        sendComment(){
            let dateOptions = {
                year: 'numeric',
                month: 'numeric',
                day: 'numeric',
                timezone: 'UTC'
            };
            let date = new Date().toLocaleString("ru", dateOptions);



            var body = {
                'company': this.$store.state.client.title,
                'region': this.$store.state.client.region,
                'datePresentation': date,
                'comment': 'Произвольный комментарий',
                'collectionId': localStorage.getItem('collectionIdForFeedback')
            };

            localStorage.removeItem('collectionIdForFeedback')

            this.$axios({
                method: 'POST',
                url: settings.apiUrl + '/feedback/',
                data: JSON.stringify(body)
            }).then(resp => {
                this.makeToast('Спасибо!', 'success', 'Ваш комментарий очень важен для нас!');
                this.animationsForm()
            })
            .catch(err => {
                this.makeToast('Ошибка!', 'danger', err);
            })

        },
        makeToast(title, variant, text,  append = false) {
            this.$bvToast.toast(text, {
                title: title,
                autoHideDelay: 3000,
                variant: variant,
                toaster: 'b-toaster-top-center',
                appendToast: append
            })
        },
        animationsForm(){
            let feedback = document.querySelector('.feedback');
            let signLink = document.querySelector('.signLink');
            let signLinkPosition = 380;
            let feedbackPosition = 0;
            let formMove = setInterval(() => {
                signLinkPosition -= 10;
                feedbackPosition -= 10
                feedback.style.left = feedbackPosition + 'px'
                signLink.style.left = signLinkPosition + 'px'
                if(signLinkPosition <= 0){
                    clearInterval(formMove);
                }
            }, 10)
        },
        getLink(){
            if(this.$v.$invalid){
                this.$v.$touch()
                return
                
            }else{
                this.makeToast('Круть!', 'success', 'Ссылка отправлена на указанный Вами e-mail');
                let signLink = document.querySelector('.signLink');
                let responseLink = document.querySelector('.responseLink');
                let opacity = 1;
                let fadeOut = setInterval(() => {
                    opacity -= 0.1;
                    signLink.style.opacity = opacity;
                    if(opacity <= 0){
                        signLink.style.display = 'none';
                        let linkOpacity = 0;
                        clearInterval(fadeOut);
                        responseLink.style.display = 'flex';
                        let fadeIn = setInterval(() =>{
                            linkOpacity += 0.1
                            responseLink.style.opacity = linkOpacity;
                            if(linkOpacity >= 0.9){
                                clearInterval(fadeIn);
                            }
                        }, 10)
                    }
                }, 10)
            }
        },
        copyLink(){
            
            navigator.clipboard.writeText(this.newLink)
                .then(() => {
                   this.makeToast('Ура!', 'success', 'Ссылка скопирована');
                })
                .catch(err => {
                    console.log('Something went wrong', err);
                });
        }
  }
}
</script>
<style lang="scss" scoped>
.container{
    overflow: hidden;
    position: relative;
}

form, .responseLink{
    width: 100%;
    height: 100vh;
    display: flex;
    justify-content: center;
    align-items: center;
    flex-direction: column;
    
    .title{
        font-size: 18px;
        line-height: 24px;
        display: flex;
        align-items: center;
        text-align: center;
        text-transform: uppercase;
        color: #fff;
        margin-bottom: 15px;
    }
    textarea{
        width: 100%;
        height: 175px;
        padding: 8px;
        font-weight: normal;
        font-size: 12px;
        line-height: 14px;
        margin-bottom: 15px;
    }
    input[type='submit']{
        width: 100%;
        height: 40px;
        display: flex;
        justify-content: center;
        align-items: center;
        color: #000;
        font-size: 18px;
        text-transform: uppercase;
    }
}
.feedback{
    position: absolute;
    left: 0;
}
.signLink{
    right: -380px;
    position: absolute;
    top: 0;
    input[type='text']{
        width: 250px;
        margin-bottom: 38px;
        height: 20px;
        background: none;
        border: none;
        border-bottom: 1px solid #fff;
        padding: 5px 0px;
        color: #fff;
        font-size: 14px;
        line-height: 16px;
        outline: none;
        height: 40px;
        min-height: 40px;
    }
    input[type='submit']{
        width: 250px;
    }
    input.error{
        border: 1px solid red;
    }
}
.responseLink{
    padding: 15px;
    left: 0;
    position: absolute;
    display: none;
    opacity: 0;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    .title{
        margin-bottom: 20px;
    }
    a{
        color: #000;
        height: 40px;
        margin-top: 50px;
        width: 250px;
        background: #fff;
        display: flex;
        justify-content: center;
        align-items: center;
        text-transform: uppercase;
    }
    #newLink{
        color: #fff;
        background: none;
        border: none;
        outline: none;
        word-break: break-all;
        &:hover{
            cursor: pointer;
        }
    }
}
</style>